Changes I made on the VM to force the use of `-cpu Haswell-v2` with `qemu-x86_64-static`:
```
$ cat /etc/binfmt.d/qemu-x86_64-static.conf 
:qemu-x86_64:M::\x7fELF\x02\x01\x01\x00\x00\x00\x00\x00\x00\x00\x00\x00\x02\x00\x3e\x00:\xff\xff\xff\xff\xff\xfe\xfe\x00\xff\xff\xff\xff\xff\xff\xff\xff\xfe\xff\xff\xff:/var/usrlocal/bin/qemu-x86_64-v2-static:F

$ cat /var/usrlocal/bin/qemu-x86_64-v2-static
#!/usr/bin/bash

exec /usr/bin/qemu-x86_64-static -cpu Haswell-v2 $@

$ sudo systemctl restart systemd-binfmt.service
```

go program:
```
package main

import (
	"log"
	"os"
	"syscall"
)

func main() {
	args := []string{os.Args[0], "-cpu", "Haswell-v2"}
	args = append(args, os.Args[1:]...)
	if err := syscall.Exec("/usr/bin/qemu-x86_64-static", args, os.Environ()); err != nil {
		log.Fatal(err)
	}
}
```
built with `GOARCH=arm64`
